class Solution:
    def minLengthAfterRemovals(self, nums: List[int]) -> int:
        n = len(nums)
        count = 0
        left, right = 0, n - 1

        while left < right:
            if nums[left] < nums[right]:
                count += 2
                left += 1
                right -= 1
            else:
                right -= 1

        return n - count
